query:
{
  functionApps(
    where: {
      configs_SOME: {
        isDeprecated: true
        OR: [
          { nodeVersion_NOT: "" }
          { pythonVersion_NOT: "" }
          { javaVersion_NOT: "" }
          { powerShellVersion_NOT: "" }
          { netFrameworkVersion_NOT: "" }
          { linuxFxVersion_NOT: "" }
        ]
      }
    }
  ) {
    ...AssetFragment
  }
}
